const applyLabelMigrations = (mapNodes) => {
  if (!Array.isArray(mapNodes)) return { nodes: [], changed: false }

  const orderedVersions = Object.keys(LABEL_MIGRATIONS_BY_VERSION)
    .map((version) => Number(version))
    .sort((a, b) => a - b)

  let changed = false
  const migratedNodes = mapNodes.map((node) => {
    let nextLabel = node.label

    orderedVersions.forEach((version) => {
      const versionMap = LABEL_MIGRATIONS_BY_VERSION[version]
      nextLabel = versionMap[nextLabel] || nextLabel
    })

    if (nextLabel === node.label) return node

    changed = true
    return {
      ...node,
      label: nextLabel,
    }
  })

  return { nodes: migratedNodes, changed }
}

const getDisplayLabelRaw = (label) => {
  const m = label.match(/\s\d+:(\d+)$/)
  if (m) return m[1]
  const pipeIdx = label.indexOf('|')
  if (pipeIdx !== -1) return label.slice(0, pipeIdx)
  return label
}

const getCodeNodeWidth = (label, nodeWidth, nodeSizeScale) => {
  const displayLabel = getDisplayLabelRaw(label)
  if (!displayLabel.includes('\n')) return nodeWidth
  const lines = displayLabel.split('\n')
  const maxLen = Math.max(...lines.map(l => l.length))
  const fontSizePx = 0.6 * 16 * nodeSizeScale
  const charWidthPx = fontSizePx * 0.6
  const paddingPx = Math.round(2 * 1.2 * 16 * nodeSizeScale)
  return Math.max(nodeWidth, Math.ceil(maxLen * charWidthPx) + paddingPx + 8)
}

const buildLayout = (nodes, topicSubdivisions = {}, nodeWidth = NODE_WIDTH, nodeHeight = NODE_HEIGHT, nodeSizeScale = 1, getNodeWidthFn = null) => {
  if (nodes.length === 0) {
    return { positions: new Map(), edges: [], bounds: null };
  }

  const nodeById = new Map(nodes.map(n => [n.id, n]))
  const getNodeHeightFn = (label) => {
    const displayLabel = getDisplayLabelRaw(label)
    const lineCount = displayLabel.split('\n').length
    if (lineCount <= 1) return nodeHeight
    const lineHeightPx = Math.round(13 * nodeSizeScale)
    return Math.max(nodeHeight, lineCount * lineHeightPx + Math.round(16 * nodeSizeScale))
  }
  const getHeight = (nodeId) => {
    const node = nodeById.get(nodeId)
    return node ? getNodeHeightFn(node.label) : nodeHeight
  }

  const root = nodes.find((node) => node.parentId == null) || nodes[0];
  const childrenById = new Map();
  nodes.forEach((node) => {
    childrenById.set(node.id, []);
  });
  nodes.forEach((node) => {
    if (node.parentId != null && childrenById.has(node.parentId) && !node.hidden) {
      childrenById.get(node.parentId).push(node);
    }
  });

  // Sort children: use topicSubdivisions order for specific parents, otherwise alphabetically
  childrenById.forEach((children, parentId) => {
    const parentNode = nodes.find(n => n.id === parentId);
    const parentLabel = parentNode?.label;
    
    // If this parent is marked for ordered children, use topicSubdivisions order; otherwise alphabetize
    if (parentLabel && topicSubdivisions[parentLabel] && ORDERED_CHILDREN_PARENTS.has(parentLabel)) {
      const definedOrder = topicSubdivisions[parentLabel];
      children.sort((a, b) => {
        // Explicit order (including admin-assigned order on global nodes) takes priority
        if (a.order !== undefined || b.order !== undefined) {
          const aOrder = a.order !== undefined ? a.order : Infinity;
          const bOrder = b.order !== undefined ? b.order : Infinity;
          if (aOrder !== bOrder) return aOrder - bOrder;
        }
        const indexA = definedOrder.indexOf(a.label);
        const indexB = definedOrder.indexOf(b.label);
        if (indexA !== -1 && indexB !== -1) return indexA - indexB;
        if (indexA !== -1) return -1;
        if (indexB !== -1) return 1;
        return a.label.localeCompare(b.label);
      });
    } else {
      // Default alphabetical sort, but respect explicit order (custom or admin-assigned)
      children.sort((a, b) => {
        if (a.order !== undefined || b.order !== undefined) {
          const aOrder = a.order !== undefined ? a.order : Infinity;
          const bOrder = b.order !== undefined ? b.order : Infinity;
          if (aOrder !== bOrder) return aOrder - bOrder;
        }
        return a.label.localeCompare(b.label);
      });
    }
  });

  const positions = new Map();
  const edges = [];
  const subtreeWidths = new Map();

  const effectiveWidth = (nodeId) => {
    const node = nodeById.get(nodeId)
    if (!node) return nodeWidth
    return getNodeWidthFn ? getNodeWidthFn(node.label) : nodeWidth
  }

  const calculateSubtreeWidth = (nodeId) => {
    const kids = childrenById.get(nodeId) || [];
    if (kids.length === 0) {
      const w = effectiveWidth(nodeId);
      subtreeWidths.set(nodeId, w);
      return w;
    }

    let totalWidth = 0;
    kids.forEach((child, index) => {
      totalWidth += calculateSubtreeWidth(child.id);
      if (index > 0) totalWidth += H_GAP;
    });

    const width = Math.max(totalWidth, effectiveWidth(nodeId));
    subtreeWidths.set(nodeId, width);
    return width;
  };

  const assignPositions = (nodeId, x, y) => {
    const kids = childrenById.get(nodeId) || [];
    const subtreeWidth = subtreeWidths.get(nodeId) || nodeWidth;
    const myWidth = effectiveWidth(nodeId);
    const nodeX = x + (subtreeWidth - myWidth) / 2;

    positions.set(nodeId, { x: nodeX, y });

    let childX = x;
    kids.forEach((child) => {
      edges.push({ from: nodeId, to: child.id });
      const childWidth = subtreeWidths.get(child.id) || nodeWidth;
      assignPositions(child.id, childX, y + getHeight(nodeId) + V_GAP);
      childX += childWidth + H_GAP;
    });
  };

  calculateSubtreeWidth(root.id);
  assignPositions(root.id, 0, 0);

  let minX = Infinity;
  let minY = Infinity;
  let maxX = -Infinity;
  let maxY = -Infinity;
  positions.forEach((pos, nodeId) => {
    minX = Math.min(minX, pos.x);
    minY = Math.min(minY, pos.y);
    maxX = Math.max(maxX, pos.x + effectiveWidth(nodeId));
    maxY = Math.max(maxY, pos.y + getHeight(nodeId));
  });

  return {
    positions,
    edges,
    bounds: { minX, minY, maxX, maxY },
  };
};

