      'Transcompilers/Transpilers': 'Tools that convert source code from one high-level language to another at a similar abstraction level.',
      'Babel': 'A JavaScript transcompiler that converts modern ES6+ code into backwards-compatible versions for older browsers.',
      'Database Systems': 'Organized collections of structured data managed through software for efficient storage and retrieval.',
      'NoSQL': 'Non-relational database systems designed for flexible, scalable storage of unstructured or semi-structured data.',
      'RDBMS (Relational DataBase Management System)': 'A database system storing data in structured tables with enforced relationships and a schema.',
      'SQL (Structured Query Language)': 'A domain-specific language for managing, querying, and manipulating relational databases.',
      'PostgreSQL': 'An advanced open-source object-relational database system known for strong standards compliance, a robust feature set, and high reliability.',
      'CLI (psql tool)': 'The psql interactive terminal for PostgreSQL. Key commands: \\l (list databases), \\d+ (describe an object), CREATE DATABASE x; (create a database).',
      'Terminal Commands': 'Command-line utilities available after installing PostgreSQL for managing databases, backups, and connections outside the psql shell.',
      'pg_dump': 'Creates a logical backup of a PostgreSQL database: pg_dump x. Flags: -Fc (custom compressed format), -h (host), -U (username), -f (output file).',
      'pg_restore': 'Restores a database from a pg_dump archive: pg_restore x. Flags: -d (database name), -h (host), -U (username).',
      'createdb': 'Creates a new PostgreSQL database from the command line: createdb x. Flags: -U (connecting user), -O (owner).',
      'psql (command)': 'Connects to a PostgreSQL database: psql x. Flags: -h (host), -U (username).',
      'Creating a Function': 'CREATE OR REPLACE FUNCTION x(args) RETURNS type AS $$ BEGIN ...body; RETURN val; END; $$ language \'plpgsql\'; — creates or replaces a stored function. Trigger functions return TRIGGER and use NEW.column = value to assign values.',
      'Creating Triggers': 'CREATE TRIGGER x BEFORE UPDATE ON table FOR EACH ROW EXECUTE PROCEDURE fn(); — links a trigger function to a table event, executing the function automatically when the event fires.',
      'Global Functions': 'Built-in PostgreSQL functions available everywhere. NOW() — returns the current date and time of the database server.',
      'OLTP (Online Transaction Processing)': 'A database system type designed for managing real-time, transaction-oriented applications such as online banking or e-commerce.',
      'Statements': 'Complete, executable SQL units that end with a semicolon, composed of a command, clauses, and expressions to perform a database operation.',
      'Data Definition Language (DDL)': 'SQL statements that define or modify the structure of database objects — CREATE, ALTER, and DROP.',
      'ALTER': 'Modifies the structure of an existing database object: ALTER TABLE x ADD COLUMN y type / DROP COLUMN y.',
      'CREATE': 'Builds a new database object. Variants: CREATE DATABASE, CREATE TABLE, CREATE VIEW, CREATE INDEX, CREATE USER.',
      'CREATE DATABASE': 'Creates a new database: CREATE DATABASE x;',
      'CREATE TABLE': 'Defines a new table with columns, types, and constraints: CREATE TABLE x (col type constraints, ..., PRIMARY KEY (col), FOREIGN KEY (col) REFERENCES table(col) ON DELETE CASCADE);. Column types: INT, VARCHAR(n), DATE, TIMESTAMP, DECIMAL(p,s), TEXT, SERIAL. Constraints: NOT NULL, PRIMARY KEY, UNIQUE, DEFAULT val, SERIAL.',
      'CREATE INDEX': 'Creates an index on a table column to speed up data retrieval.',
      'CREATE VIEW': 'Creates a virtual table based on a SELECT query.',
      'CREATE USER': 'Creates a new database user: CREATE USER x WITH PASSWORD \'pass\';',
      'DROP': 'Permanently deletes a database object. DROP TABLE x (table and data), DROP DATABASE x, DROP INDEX (index from table).',
      'Data Manipulation Language (DML)': 'SQL statements for managing data within tables — SELECT, INSERT INTO, UPDATE, and DELETE FROM.',
      'SELECT': 'Retrieves data: SELECT col1, col2 FROM table. Supports FROM, WHERE, ORDER BY x ASC/DESC, LIMIT n, DISTINCT, GROUP BY, HAVING, and join clauses.',
      'WHERE': 'Filters rows by a condition. Operators: LIKE \'%val%\', OR, AND, BETWEEN y AND z, IS NULL / IS NOT NULL. Example: WHERE column_name < 2000.',
      'Group By/Having': 'GROUP BY x groups rows with the same value for use with aggregate functions. HAVING x filters those groups — like WHERE but applied after grouping.',
      'Join Clauses': 'Combine rows from multiple tables based on a related column.',
      'INNER JOIN': 'Returns only rows with matching values in both tables: x INNER JOIN y ON x.col = y.col. Shortcut: JOIN.',
      'LEFT JOIN': 'Returns all rows from the left table and matching rows from the right; unmatched right rows are NULL.',
      'RIGHT JOIN': 'Returns all rows from the right table and matching rows from the left; unmatched left rows are NULL.',
      'FULL OUTER JOIN': 'Returns all rows from both tables, with NULLs where there is no match. Combines LEFT and RIGHT JOIN. Shortcut: FULL JOIN.',
      'CROSS JOIN': 'Returns the Cartesian product of two tables — every row from the first paired with every row from the second.',
      'INSERT INTO': 'Adds rows to a table: INSERT INTO x (col1, col2) VALUES (val1, val2), (val3, val4);. Foreign key values can be provided via a subquery.',
      'UPDATE': 'Modifies existing rows: UPDATE x SET col = val WHERE col = filter_val;. Without WHERE, all rows are updated.',
      'DELETE FROM': 'Removes rows from a table: DELETE FROM x WHERE col = val;.',
      'Data Control Language (DCL)': 'SQL statements that control access rights and permissions for database objects.',
      'USE': 'Selects a specific database for the current session: USE x;',
      'GRANT': 'Gives privileges to a user: GRANT ALL PRIVILEGES ON DATABASE x TO user;',
      'Transaction Control Language (TCL)': 'SQL statements that manage transactions — sequences of DML statements treated as a single atomic unit.',
      'Database': 'The structural and logical components of a PostgreSQL database, including its schema and objects.',
      'Database Structure/Schema': 'The framework that organizes and defines the structure of stored data, including tables, relationships, and constraints.',
      'Database Objects': 'Named structures that store or reference data, including tables, views, indexes, functions, and schemas.',
      'Tables': 'Organize data into a structured grid of rows and columns, the fundamental storage unit in a relational database.',
      'Primary Key': 'A column or set of columns that uniquely identifies each record within a table.',
      'Foreign Key': 'A column that references the primary key of another table, linking data between the two.',
      'Views': 'Virtual tables defined by a query, used to simplify complex queries or restrict data access.',
      'SQL Functions': 'Database functions that perform calculations or manipulations on data, returning a single value — either aggregate (over a set of rows) or scalar (on a single value).',
      'Aggregate Functions': 'Operate on a set of rows and return a single summary value.',
      'AVG()': 'Returns the average value of a numeric column: AVG(x).',
